"""Part V, Chapter 36 entries — modular equations supplement (curated LaTeX)."""

from __future__ import annotations

TOPICS_C36 = ["modular-equations-supplement"]


def rec(entry_id: str, content: str) -> dict:
    return {"id": entry_id, "content": content, "topics": TOPICS_C36}


CHAPTER_36 = [
    rec("RN-P5-C36-Entry01", r"If $\beta$ has degree $3$ over $\alpha$, then $\displaystyle\int_0^{\theta}\frac{d\phi}{\sqrt{1-\alpha\sin^2\phi}}=\frac{1}{\sqrt{3}}\int_0^{\varphi}\frac{d\psi}{\sqrt{1-\beta\sin^2\psi}}$, where $\tan\theta=\tan(\varphi+\psi)+\tan(\varphi-\psi)+2(1-\alpha)\tan\varphi\tan\psi/(1-(1-\alpha)\tan^2\varphi\tan^2\psi)$."),
    rec("RN-P5-C36-Entry02", r"$\psi(-q)\psi(-q^2)=\psi(q^2)\psi(q^8)+q\,\psi(q^4)\psi(q^{16})$."),
    rec("RN-P5-C36-Entry03", r"$\psi(q)-q\psi(q^4)=\varphi(-q^2)\varphi(-q^8)/\varphi(-q)\varphi(-q^4)$."),
    rec("RN-P5-C36-Entry04", r"$\bigl(\varphi(q)\varphi(-q)-\varphi(-q^5)\varphi(q^5)\bigr)^2=8\,\varphi(-q^5)\varphi(q^5)$."),
    rec("RN-P5-C36-Entry05", r"$\varphi^2(q)\psi(-q)+q\varphi^2(q^3)\psi(-q^3)/\psi(-q^3)=1-5\sum_{k=0}^{\infty}(-1)^k(4k+1)q^{3k(k+1)/2}$."),
    rec("RN-P5-C36-Entry06", r"If $\beta$ has degree $3$ over $\alpha$, then $\displaystyle\frac{\varphi(e^{-\pi\sqrt{3}})}{\varphi(e^{-\pi})}=\frac{3^{1/8}}{2^{1/3}(3\sqrt{3}-5)^{1/4}}$."),
    rec("RN-P5-C36-Entry07", r"Let $m$ and $n$ be positive numbers with $m-n=1$. Define $\sin^2\theta=m^{1/3}\sin^2\varphi$ and $\cos^2\theta=n^{1/3}\cos^2\varphi$. Then $\displaystyle\frac{\sqrt{m-\sin^2\theta}}{\sqrt{m-\sin^2\varphi}}=\frac{m+n}{2}\,\frac{{}_2F_1(\tfrac12,\tfrac12;1;\sin^2\varphi)}{{}_2F_1(\tfrac12,\tfrac12;1;\sin^2\theta)}$."),
    rec("RN-P5-C36-Entry08", r"Let $0<n<\tfrac12$ and set $p=(2+n)/(1+2n)$. Then $p=\tfrac12\bigl(1+\sqrt{1-n}+\sqrt{2+n+2\sqrt{1-n+n^2}}\bigr)$."),
    rec("RN-P5-C36-Entry09", r"If $\beta$ has degree $3$ over $\alpha$, with $m=(\alpha/\beta)^{1/3}$ and $n=\beta^{1/3}$, then $m^3+2m^2n^2-2mn-n^4=0$."),
    rec("RN-P5-C36-Entry10", r"$\displaystyle\frac{\varphi(q)\varphi(q^3)}{\varphi(q^2)\varphi(q^6)}=\frac{\psi(q)\psi(q^3)}{\psi(q^2)\psi(q^6)}$."),
    rec("RN-P5-C36-Entry11", r"If $\beta$ has degree $3$ over $\alpha$, define $x=(\alpha/\beta)^{1/3}$ and $y=(\beta/\alpha)^{1/3}$. Then $x^2y+xy^2+3xy-3x-3y+9=0$."),
    rec("RN-P5-C36-Entry12", r"If $\beta$ has degree $3$ over $\alpha$, then $(\alpha/\beta)^{1/3}+(\beta/\alpha)^{1/3}+3(\alpha\beta)^{1/3}(1-\alpha)(1-\beta)=3$."),
    rec("RN-P5-C36-Entry13", r"If $\beta$ has degree $3$ over $\alpha$, then $(\alpha/\beta)^{2/3}+(\beta/\alpha)^{2/3}+3(\alpha\beta)^{2/3}(1-\alpha)(1-\beta)=3$."),
    rec("RN-P5-C36-Entry14", r"$\displaystyle\frac{f(-q,-q^6)}{f(-q^3,-q^4)}=\frac{f(-q^2,-q^5)}{f(-q^3,-q^4)}+\frac{2q^{2/3}f(-q^9,-q^{12})}{f(-q^3,-q^{18})}$."),
    rec("RN-P5-C36-Entry15", r"$\displaystyle\frac{\varphi(q)\varphi(q^5)}{\varphi(q^2)\varphi(q^{10})}=1+6\sum_{n=1}^{\infty}\frac{q^{5n^2}}{1+q^{5n}}$."),
    rec("RN-P5-C36-Entry16", r"$\displaystyle\frac{\psi(q)\psi(q^5)}{\varphi(q)\varphi(q^5)}=\sum_{n=0}^{\infty}\frac{q^{4n+1}}{1-q^{8n+4}}+\sum_{n=0}^{\infty}\frac{q^{4n+3}}{1-q^{8n+4}}$."),
    rec("RN-P5-C36-Entry17", r"$\displaystyle\frac{\varphi(q)\varphi(q^5)}{\psi(q)\psi(q^5)}=\sum_{n=0}^{\infty}\frac{q^{4n+1}}{1+q^{4n+1}}+\sum_{n=0}^{\infty}\frac{q^{4n+3}}{1+q^{4n+3}}-\sum_{n=0}^{\infty}\frac{q^{4n+2}}{1+q^{4n+2}}-\sum_{n=0}^{\infty}\frac{q^{4n+4}}{1+q^{4n+4}}$."),
    rec("RN-P5-C36-Entry18", r"$\displaystyle\frac{\psi(q)\psi(q^5)}{\varphi(q)\varphi(q^5)}=\sum_{n=0}^{\infty}\frac{q^{4n+1}}{1-q^{8n+4}}-\sum_{n=0}^{\infty}\frac{q^{4n+3}}{1-q^{8n+4}}+\sum_{n=0}^{\infty}\frac{q^{4n+5}}{1-q^{8n+4}}-\sum_{n=0}^{\infty}\frac{q^{4n+7}}{1-q^{8n+4}}$."),
    rec("RN-P5-C36-Entry19", r"$\displaystyle\frac{\varphi(q)\varphi(q^5)}{\psi(q)\psi(q^5)}=\sum_{n=0}^{\infty}\frac{q^{4n+1}}{1+q^{4n+1}}-\sum_{n=0}^{\infty}\frac{q^{4n+3}}{1+q^{4n+3}}+\sum_{n=0}^{\infty}\frac{q^{4n+5}}{1+q^{4n+5}}-\sum_{n=0}^{\infty}\frac{q^{4n+7}}{1+q^{4n+7}}$."),
    rec("RN-P5-C36-Entry20", r"If $\beta$ has degree $5$ over $\alpha$, then $(\alpha/\beta)^{1/5}+(\beta/\alpha)^{1/5}+5(\alpha\beta)^{1/5}(1-\alpha)(1-\beta)=5$."),
    rec("RN-P5-C36-Entry21", r"$\displaystyle\frac{\varphi(q)\varphi(q^7)}{\varphi(q^2)\varphi(q^{14})}=\frac{\psi(q)\psi(q^7)}{\psi(q^2)\psi(q^{14})}$."),
    rec("RN-P5-C36-Entry22", r"$\displaystyle\frac{f(-q,-q^7)}{f(-q^3,-q^5)}=\frac{f(-q^2,-q^6)}{f(-q^3,-q^5)}+\frac{2q^{1/3}f(-q^8,-q^{14})}{f(-q^3,-q^{21})}$."),
    rec("RN-P5-C36-Entry23", r"The equation $x^5+y^5+5xy(x+y)+5x^2y^2=1$ is a modular equation of composite degree."),
    rec("RN-P5-C36-Entry24", r"If $\beta$ has degree $16$ over $\alpha$, then $(\alpha/\beta)^{1/4}+(\beta/\alpha)^{1/4}+4(\alpha\beta)^{1/4}(1-\alpha)(1-\beta)=4$."),
    rec("RN-P5-C36-Entry25", r"If $\beta$ has degree $7$ over $\alpha$, then $(\alpha/\beta)^{1/7}+(\beta/\alpha)^{1/7}+7(\alpha\beta)^{1/7}(1-\alpha)(1-\beta)=7$."),
    rec("RN-P5-C36-Entry26", r"If $\beta$ has degree $7$ over $\alpha$, then $(\alpha/\beta)^{2/7}+(\beta/\alpha)^{2/7}+7(\alpha\beta)^{2/7}(1-\alpha)(1-\beta)=7$."),
    rec("RN-P5-C36-Entry27", r"If $\gamma$ has degree $9$ over $\alpha$, with $m=z_1/z_3$ and $m'=z_2/z_9$, then $m^3+m'^3+3mm'(m+m')-3m-3m'+9=0$."),
    rec("RN-P5-C36-Entry28", r"If $m$ is the multiplier of degree $9$ and $\gamma$ has degree $9$, then $(\gamma/\alpha)^{1/3}+(\alpha/\gamma)^{1/3}+3(\alpha\gamma)^{1/3}(1-\alpha)(1-\gamma)=3$."),
    rec("RN-P5-C36-Entry29", r"$\displaystyle\frac{\varphi(q)\varphi(q^9)}{\varphi(q^3)\varphi(q^{27})}=\frac{\psi(q)\psi(q^9)}{\psi(q^3)\psi(q^{27})}$."),
    rec("RN-P5-C36-Entry30", r"If $\beta$ has degree $11$ over $\alpha$, then $(\alpha/\beta)^{1/11}+(\beta/\alpha)^{1/11}+11(\alpha\beta)^{1/11}(1-\alpha)(1-\beta)=11$."),
    rec("RN-P5-C36-Entry31", r"$\displaystyle\frac{\varphi(q)\varphi(q^{11})}{\varphi(q^2)\varphi(q^{22})}=\frac{\psi(q)\psi(q^{11})}{\psi(q^2)\psi(q^{22})}$."),
    rec("RN-P5-C36-Entry32", r"$\displaystyle\frac{f(-q,-q^{11})}{f(-q^5,-q^7)}=\frac{f(-q^2,-q^{10})}{f(-q^5,-q^7)}+\frac{2q^{1/5}f(-q^{12},-q^{22})}{f(-q^5,-q^{35})}$."),
    rec("RN-P5-C36-Entry33", r"If $n$ is real, then $\displaystyle\sum_{k=1}^{\infty}\frac{(-1)^{k-1}k^n}{1-q^k}=\frac{B_{n+1}}{n+1}+\sum_{j=1}^{\infty}\sigma_n(j)q^j$ for $|q|<1$."),
    rec("RN-P5-C36-Entry34", r"If $\left(\frac{n}{p}\right)$ denotes the Legendre symbol, then $\displaystyle\sum_{n=1}^{p-1}\left(\frac{n}{p}\right)\frac{q^n}{1-q^n}=0$ for an odd prime $p$."),
    rec("RN-P5-C36-Entry35", r"If $\left(\frac{n}{p}\right)$ denotes the Legendre symbol, then $\displaystyle\sum_{n=1}^{p-1}\left(\frac{n}{p}\right)\frac{q^{n^2}}{1-q^{n^2}}=0$ for an odd prime $p$."),
    rec("RN-P5-C36-Entry36", r"$\displaystyle\frac{\varphi(q)\varphi(q^{13})}{\varphi(q^2)\varphi(q^{26})}=\frac{\psi(q)\psi(q^{13})}{\psi(q^2)\psi(q^{26})}$."),
    rec("RN-P5-C36-Entry37", r"$\displaystyle\frac{f(-q,-q^{13})}{f(-q^5,-q^9)}=\frac{f(-q^2,-q^{12})}{f(-q^5,-q^9)}+\frac{2q^{1/6}f(-q^{14},-q^{26})}{f(-q^5,-q^{39})}$."),
    rec("RN-P5-C36-Entry38", r"$\displaystyle\frac{\varphi(q)\varphi(q^{17})}{\varphi(q^2)\varphi(q^{34})}=\frac{\psi(q)\psi(q^{17})}{\psi(q^2)\psi(q^{34})}$."),
    rec("RN-P5-C36-Entry39", r"$\displaystyle\frac{f(-q,-q^{17})}{f(-q^5,-q^{13})}=\frac{f(-q^2,-q^{16})}{f(-q^5,-q^{13})}+\frac{2q^{1/8}f(-q^{18},-q^{34})}{f(-q^5,-q^{51})}$."),
    rec("RN-P5-C36-Entry40", r"If $P$ is defined by (39.1), then $P^2-P=4Q^2$ where $P$ and $Q$ are eta-function ratios of degree $19$."),
    rec("RN-P5-C36-Entry41", r"Let $P=\varphi(q)/\varphi(q^5)$ and $Q=\varphi(q^2)/\varphi(q^{10})$. Then $P^4Q^4-P^6+8P^4Q^2=-49P^2Q^2+Q^6-8P^2Q^4$."),
    rec("RN-P5-C36-Entry42", r"Let $P$ and $Q$ be defined by (42.1) and (42.2), respectively. Then $P^4Q^4+3PQ=P^6+Q^6$."),
    rec("RN-P5-C36-Entry43", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $3$, $1$, $5$, and $15$, respectively, then $(\alpha/\gamma)^{1/3}+(\gamma/\alpha)^{1/3}+(\beta/\delta)^{1/5}+(\delta/\beta)^{1/5}+5(\alpha\beta\gamma\delta)^{1/15}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=5$."),
    rec("RN-P5-C36-Entry44", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $5$, $1$, $3$, and $15$, respectively, then $(\alpha/\gamma)^{1/5}+(\gamma/\alpha)^{1/5}+(\beta/\delta)^{1/3}+(\delta/\beta)^{1/3}+5(\alpha\beta\gamma\delta)^{1/15}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=5$."),
    rec("RN-P5-C36-Entry45", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $3$, $7$, and $21$, respectively, then $(\beta/\gamma)^{1/3}+(\gamma/\beta)^{1/3}+(\alpha/\delta)^{1/7}+(\delta/\alpha)^{1/7}+7(\alpha\beta\gamma\delta)^{1/21}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=7$."),
    rec("RN-P5-C36-Entry46", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $7$, $1$, $3$, and $21$, respectively, then $(\alpha/\gamma)^{1/7}+(\gamma/\alpha)^{1/7}+(\beta/\delta)^{1/3}+(\delta/\beta)^{1/3}+7(\alpha\beta\gamma\delta)^{1/21}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=7$."),
    rec("RN-P5-C36-Entry47", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $3$, $1$, $11$, and $33$, respectively, then $(\alpha/\gamma)^{1/3}+(\gamma/\alpha)^{1/3}+(\beta/\delta)^{1/11}+(\delta/\beta)^{1/11}+11(\alpha\beta\gamma\delta)^{1/33}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=11$."),
    rec("RN-P5-C36-Entry48", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $5$, $1$, $7$, and $35$, respectively, then $(\alpha/\gamma)^{1/5}+(\gamma/\alpha)^{1/5}+(\beta/\delta)^{1/7}+(\delta/\beta)^{1/7}+7(\alpha\beta\gamma\delta)^{1/35}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=7$."),
    rec("RN-P5-C36-Entry49", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $5$, $1$, $11$, and $55$, respectively, then $(\alpha/\gamma)^{1/5}+(\gamma/\alpha)^{1/5}+(\beta/\delta)^{1/11}+(\delta/\beta)^{1/11}+11(\alpha\beta\gamma\delta)^{1/55}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=11$."),
    rec("RN-P5-C36-Entry50", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $5$, $7$, and $35$, respectively, then $(\beta/\gamma)^{1/5}+(\gamma/\beta)^{1/5}+(\alpha/\delta)^{1/7}+(\delta/\alpha)^{1/7}+7(\alpha\beta\gamma\delta)^{1/35}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=7$."),
    rec("RN-P5-C36-Entry51", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $13$, $3$, and $39$, respectively, then $(\beta/\gamma)^{1/13}+(\gamma/\beta)^{1/13}+(\alpha/\delta)^{1/3}+(\delta/\alpha)^{1/3}+13(\alpha\beta\gamma\delta)^{1/39}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=13$."),
    rec("RN-P5-C36-Entry52", r"If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $13$, $5$, and $65$, respectively, then $(\beta/\gamma)^{1/13}+(\gamma/\beta)^{1/13}+(\alpha/\delta)^{1/5}+(\delta/\alpha)^{1/5}+13(\alpha\beta\gamma\delta)^{1/65}(1-\alpha)(1-\beta)(1-\gamma)(1-\delta)=13$."),
    rec("RN-P5-C36-Entry53", r"Let $P=1+(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=4\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}+\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=4\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. With the plus signs in (53.1)–(53.3), if $\beta$ has degree $15$ over $\alpha$, then $P(P^2-Q)+R=0$."),
    rec("RN-P5-C36-Entry54", r"Let $P=1+(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=4\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}+\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=4\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. With the plus signs, if $\beta$ has degree $31$ over $\alpha$, then $P^2-Q=\sqrt{PR}$."),
    rec("RN-P5-C36-Entry55", r"Let $P=1+(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=4\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}+\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=4\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. With the plus signs, if $\beta$ has degree $47$ over $\alpha$, then $P^2-Q-PR^{1/3}-2R^{2/3}=0$."),
    rec("RN-P5-C36-Entry56", r"Let $P=1+(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=4\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}+\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=4\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. With the minus signs, if $\beta$ has degree $71$ over $\alpha$, then $P^3-R^{1/3}(4P^2+Q)+2P^{2/3}R-Q=0$."),
    rec("RN-P5-C36-Entry57", r"Let $P=1+(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=4\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}+\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=4\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. With the plus signs, if $\beta$ has degree $95$ over $\alpha$, then $(P^2-Q)^2P-P^{1/3}(5P^4-4QP^2)-QP^2R^{1/3}-P(P^2-Q)-5P^{4/3}R-2P^{5/3}=0$."),
    rec("RN-P5-C36-Entry58", r"Let $P=1-(\alpha/\beta)^{1/8}-\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=16\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}-\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=16\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. If $\beta$ has degree $19$ over $\alpha$, then $P^2R-QR=0$."),
    rec("RN-P5-C36-Entry59", r"Let $P=1-(\alpha/\beta)^{1/8}-\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=16\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}-\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=16\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. If $\beta$ has degree $27$ over $\alpha$, then $P^4-RP^{2/9}(29P^4+11P^2Q+Q^2)-11R^2P^2-3R^{4/9}(PQ+R)=0$."),
    rec("RN-P5-C36-Entry60", r"Let $P=1-(\alpha/\beta)^{1/8}-\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=16\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}-\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=16\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. If $\beta$ has degree $35$ over $\alpha$, then $P^4-R^{1/3}(5P^2+PQ)+2P^2R^{2/3}-RP-R^{4/3}=0$."),
    rec("RN-P5-C36-Entry61", r"Let $P=1-(\alpha/\beta)^{1/8}-\{(1-\alpha)(1-\beta)\}^{1/8}$, $Q=16\{(\alpha/\beta)^{1/8}+\{(1-\alpha)(1-\beta)\}^{1/8}-\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=16\{\alpha\beta(1-\alpha)(1-\beta)\}^{1/8}$. If $\beta$ has degree $59$ over $\alpha$, then $P^5-R^{-1}(14P^4+9P^2Q+Q^2)+R^{2/3}P(19P^2+Q)+6R(7P^2+Q)+4PR^{4/3}-8R^{5/3}=0$."),
    rec("RN-P5-C36-Entry62", r"Let $P=1-\sqrt{\alpha/\beta}-\sqrt{(1-\alpha)(1-\beta)}$, $Q=64\{\sqrt{\alpha/\beta}+\sqrt{(1-\alpha)(1-\beta)}-7\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=32\sqrt{\alpha\beta(1-\alpha)(1-\beta)}$. If $\beta$ has degree $9$ over $\alpha$, then $P^4-R(14P^2+PQ)-3R^2=0$."),
    rec("RN-P5-C36-Entry63", r"Let $P=1-\sqrt{\alpha/\beta}-\sqrt{(1-\alpha)(1-\beta)}$, $Q=64\{\sqrt{\alpha/\beta}+\sqrt{(1-\alpha)(1-\beta)}-7\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=32\sqrt{\alpha\beta(1-\alpha)(1-\beta)}$. If $\beta$ has degree $13$ over $\alpha$, then $\sqrt{P(P^2+8R)}-\sqrt{R(11P^2+Q)}=0$."),
    rec("RN-P5-C36-Entry64", r"Let $P=1-\sqrt{\alpha/\beta}-\sqrt{(1-\alpha)(1-\beta)}$, $Q=64\{\sqrt{\alpha/\beta}+\sqrt{(1-\alpha)(1-\beta)}-7\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=32\sqrt{\alpha\beta(1-\alpha)(1-\beta)}$. If $\beta$ has degree $17$ over $\alpha$, then $P^4-P^{1/3}(10P^2+Q)+6R^{2/3}P+12P=0$."),
    rec("RN-P5-C36-Entry65", r"Let $P=1-\sqrt{\alpha/\beta}-\sqrt{(1-\alpha)(1-\beta)}$, $Q=64\{\sqrt{\alpha/\beta}+\sqrt{(1-\alpha)(1-\beta)}-7\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=32\sqrt{\alpha\beta(1-\alpha)(1-\beta)}$. If $\beta$ has degree $29$ over $\alpha$, then $\sqrt{P(P^2+17PP^{2/3}-9P^{4/3})}-P^{2/3}(9P^2+Q-13PP^{2/3}+15P^{4/3})=0$."),
    rec("RN-P5-C36-Entry66", r"Let $P=1-\sqrt{\alpha/\beta}-\sqrt{(1-\alpha)(1-\beta)}$, $Q=64\{\sqrt{\alpha/\beta}+\sqrt{(1-\alpha)(1-\beta)}-7\sqrt{\alpha\beta(1-\alpha)(1-\beta)}\}$, and $R=32\sqrt{\alpha\beta(1-\alpha)(1-\beta)}$. If $\beta$ has degree $37$ over $\alpha$, then $P^3-R(19P^2+Q)-3PR^{2/3}-25R-M(19P^2-Q)+M=0$ for a multiplier $M$."),
    rec("RN-P5-C36-Lemma67", r"$\varphi(-q^2)f(q^4)-f(q,q^4)-q^2f(q^2,q^8)=0$."),
    rec("RN-P5-C36-Entry68", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $3$, $11$, and $33$, respectively, then $P^2-Q-PR-4R^{2/3}=0$."),
    rec("RN-P5-C36-Entry69", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $5$, $7$, and $35$, respectively, then $P^2-Q-PR+PR^{2/3}=0$."),
    rec("RN-P5-C36-Entry70", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $5$, $11$, and $55$, respectively, then $P^2-R(4P^2+Q)-PR^{2/3}+4R^2=0$."),
    rec("RN-P5-C36-Entry71", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $3$, $17$, and $51$, respectively, then $P^4-RPP^2+Q+6R^2P-12R^2=0$."),
    rec("RN-P5-C36-Entry72", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $3$, $3$, and $9$, respectively, then $P^4-PQ+3R^2=0$."),
    rec("RN-P5-C36-Entry73", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $3$, $9$, and $27$, respectively, then $P^4-R(P^2+5P^2Q)+9R^2P^2+6R^3=0$."),
    rec("RN-P5-C36-Entry74", r"Let $P=1+(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}$, $Q=4\{(\alpha/\gamma)^{1/4}+\{(1-\alpha)(1-\gamma)\}^{1/4}+\sqrt{\alpha\gamma(1-\alpha)(1-\gamma)}\}$, and $R=4\{\alpha\gamma(1-\alpha)(1-\gamma)\}^{1/4}$. If $\alpha$, $\beta$, $\gamma$, and $\delta$ have degrees $1$, $5$, $5$, and $25$, respectively, then $P^4-PR(5P^2+Q)-P^2R^2+5PR^2-R^4=0$."),
    rec("RN-P5-C36-Entry75", r"If $\beta$ has degree $49$ over $\alpha$, put $F=(\alpha/\beta)^{1/4}+\{(1-\alpha)(1-\beta)\}^{1/4}$. Then $(F+\sqrt{F^2-4})^2-(4(2+F^2)+13R^2)=0$, where $R$ is the multiplier of degree $49$."),
    rec("RN-P5-C36-Entry76", r"With $x=\sum_{n=0}^{\infty}(2n+1)\cosh((2n+1)y/2)/(2n+1)!$ and $y=\sum_{n=0}^{\infty}(2n+1)\sinh((2n+1)y/2)/(2n+1)!$, then $x^2-y^2=1$."),
    rec("RN-P5-C36-Entry77", r"In the notation of Entry 76, $\displaystyle\frac{dy}{dx}=\frac{1}{\sqrt{x^2-1}}$ and $\displaystyle\frac{dx}{dy}=\frac{1}{\sqrt{y^2+1}}$."),
    rec("RN-P5-C36-Entry78", r"With $x$, $y$, and $z$ as in Entry 76, $\displaystyle\sum_{n=0}^{\infty}(2n+1)^k\cosh((2n+1)y/2)$ equals a polynomial in $x$, $y$, and $z$ whose $n$th term involves $(2n+1)^k$."),
    rec("RN-P5-C36-Entry79", r"For $0<x<1$, suppose $\displaystyle\frac{1+\sin\beta}{1-\sin\beta}=\frac{1+\sin\alpha}{1-\sin\alpha}\cdot\frac{1+x\sin\theta}{1-x\sin\theta}$ where $0<\alpha,\beta,\theta<\pi/2$. Then $\displaystyle\int_0^{\theta}\frac{d\phi}{\sqrt{1-x^2\sin^2\phi}}=\frac{1+x}{1-x}\int_0^{\alpha}\frac{d\psi}{\sqrt{1-\sin^2\psi}}$."),
    rec("RN-P5-C36-Entry80", r"For $0<x<1$, suppose $\displaystyle\frac{1+\sin\beta}{1+\sin\alpha}=\frac{1+x\sin\theta}{1-x\sin\theta}$ where $0<\alpha,\beta,\theta<\pi/2$. Then $\displaystyle\int_0^{\theta}\frac{d\phi}{\sqrt{1-x^2\sin^2\phi}}=\frac{1+x}{1-x}\int_0^{\alpha}\frac{d\psi}{\sqrt{1-\sin^2\psi}}$."),
    rec("RN-P5-C36-Entry81", r"Let $F(x)$, $0<x<1$, be defined by Entry 76. Put $F(x)=t$. Then $\displaystyle\frac{1+(1-t)(1-t+2t^2)}{1+(1-t)(1-t-2t^2)}\approx\pi$."),
    rec("RN-P5-C36-Entry82", r"Let $F(x)$ be defined by Entry 76. Then $F(1-e^{-\pi})=\dfrac{10+\sqrt{36+\pi^2}}{2\sqrt{60+\pi^2}}$."),
]
